# V0011
# Audit reference: Self-contained GitHub delivery for the complete JPL-only V0011 half-Sun publication program.
from __future__ import annotations

import base64
import gzip
import hashlib
from pathlib import Path

PAYLOAD = ""
EXPECTED_SHA256 = "5c20ef8ef4dc29a998e29623e2c7ff9adbe477054c1191c5a9ece5f576f93817"
EXPANDED_PATH = Path("/content/MERCURY_PARALLAX_PUBLICATION_V0011_FULL.py")

source = gzip.decompress(base64.b64decode(PAYLOAD))
digest = hashlib.sha256(source).hexdigest()
if digest != EXPECTED_SHA256:
    raise RuntimeError(f"V0011 source verification failed: expected {EXPECTED_SHA256}, received {digest}")
text = source.decode("utf-8")
if not text.startswith("# V0011\n") or not text.rstrip().endswith("# V0011"):
    raise RuntimeError("V0011 boundary audit failed.")
compile(text, str(EXPANDED_PATH), "exec")
EXPANDED_PATH.write_text(text, encoding="utf-8")
print(f"Expanded complete V0011 source: {EXPANDED_PATH}")
print(f"Verified V0011 SHA-256: {digest}")
exec(compile(text, str(EXPANDED_PATH), "exec"), {"__name__": "__main__", "__file__": str(EXPANDED_PATH)})
